// Get current technology detection results
const currentDetections = $('🔍 Discover Technology Adopters').first().json.data || [];

// Get previous scan domains from Google Sheets
const previousItems = $('📑 Read Previous Scan Data').all();
const previousDomains = new Set(
  previousItems.map(item => item.json.domain).filter(Boolean)
);

// Find new adoptions (domains not seen before)
const newAdoptions = currentDetections.filter(
  detection => !previousDomains.has(detection.attributes?.domain)
);

// Return new adoptions for downstream processing
return newAdoptions.map(detection => ({
  json: {
    domain: detection.attributes?.domain || detection.domain,
    tool_name: $('🔀 Split by Tool').first().json.tool_name,
    tech_id: $('🔀 Split by Tool').first().json.tech_id,
    detected_at: detection.attributes?.first_detected_at || new Date().toISOString(),
    is_new: true
  }
}));

const results = [];

const toolName = $('⚙️ Compare & Detect New Adoptions').first().json.tool_name;

for (const item of $input.all()) {

  const company = item.json.data?.[0]?.attributes || {};

  const domain = company.domain || '';
  const companyName = company.company_name || company.friendly_company_name || domain;

  const industry = company.industry || 'technology';
  const size = company.employee_count || 'unknown';
  const description = company.description || '';

  const prompt = `You are a B2B partnerships expert. Draft a concise, friendly co-marketing outreach email.

Context:
- We noticed that ${companyName} (${domain}) recently adopted ${toolName}.
- Our product is complementary to ${toolName} and we believe there is a strong co-marketing opportunity.
- Company industry: ${industry}
- Company size: ${size} employees
- Company description: ${description}

Requirements:
- Subject line included at the top as "Subject: ..."
- Professional but warm tone
- Mention the complementary nature of our tools
- Propose a specific co-marketing idea (joint webinar, co-authored content, integration showcase)
- Keep it under 200 words
- End with a clear call-to-action`;

  results.push({
    json: {
      prompt,
      company_name: companyName,
      domain: domain,
      tool_name: toolName,
      industry: industry,
      employee_count: size
    }
  });

}

return results;

